37	func parseExecuteLoopSpec(cmd *cobra.Command, treatPassthroughAsOpaque bool) (executeloop.ExecuteLoopSpec, executeloop.DispatchOptions, error) {
38		projectRoot, _ := cmd.Flags().GetString("project")
39		fromRev, _ := cmd.Flags().GetString("from")
40		harness, _ := cmd.Flags().GetString("harness")
41		model, _ := cmd.Flags().GetString("model")
42		profile, _ := cmd.Flags().GetString("profile")
43		provider, _ := cmd.Flags().GetString("provider")
44		effort, _ := cmd.Flags().GetString("effort")
45		once, _ := cmd.Flags().GetBool("once")
46		watch, _ := cmd.Flags().GetBool("watch")
47		rawIdleInterval, _ := cmd.Flags().GetDuration("idle-interval")
48		asJSON, _ := cmd.Flags().GetBool("json")
49		dispatchJSON := ""
50		if asJSON {
51			dispatchJSON = "true"
52		}
53		local, _ := cmd.Flags().GetBool("local")
54		noReview, _ := cmd.Flags().GetBool("no-review")
55		noReviewAck, _ := cmd.Flags().GetBool("no-review-i-know-what-im-doing")
56		reviewHarness, _ := cmd.Flags().GetString("review-harness")
57		reviewModel, _ := cmd.Flags().GetString("review-model")
58		maxCostUSD, _ := cmd.Flags().GetFloat64("max-cost")
59		maxBeadCostUSD, _ := cmd.Flags().GetFloat64("max-bead-cost")
60		maxRecoveryCostUSD, _ := cmd.Flags().GetFloat64("max-recovery-cost")
61		requestTimeout, _ := cmd.Flags().GetDuration("request-timeout")
62		rateLimitMaxWait, _ := cmd.Flags().GetDuration("rate-limit-max-wait")
63		minPower, _ := cmd.Flags().GetInt("min-power")
64		maxPower, _ := cmd.Flags().GetInt("max-power")
65	
66		if noReview && !noReviewAck {
67			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--no-review requires --no-review-i-know-what-im-doing (break-glass acknowledgement)")
68		}
69		if once && watch {
70			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--once and --watch are mutually exclusive")
71		}
72		if !watch && cmd.Flags().Changed("idle-interval") {
73			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, fmt.Errorf("--idle-interval only applies in watch mode; pass --watch")
74		}
75	
76		mode := executeloop.ModeDrain
77		var idleInterval executeloop.Duration
78		if once {
79			mode = executeloop.ModeOnce
80		} else if watch {
81			mode = executeloop.ModeWatch
82			idleInterval = executeloop.Duration{Duration: rawIdleInterval}
83		}
84	
85		spec := executeloop.ExecuteLoopSpec{
86			ProjectRoot:        projectRoot,
87			Harness:            harness,
88			Model:              model,
89			Profile:            profile,
90			Provider:           provider,
91			Effort:             effort,
92			Mode:               mode,
93			IdleInterval:       idleInterval,
94			NoReview:           noReview,
95			ReviewHarness:      reviewHarness,
96			ReviewModel:        reviewModel,
97			OpaquePassthrough:  treatPassthroughAsOpaque,
98			MaxCostUSD:         maxCostUSD,
99			MaxBeadCostUSD:     maxBeadCostUSD,
100			MaxRecoveryCostUSD: maxRecoveryCostUSD,
101			RequestTimeout:     executeloop.Duration{Duration: requestTimeout},
102			RateLimitMaxWait:   executeloop.Duration{Duration: rateLimitMaxWait},
103			MinPower:           minPower,
104			MaxPower:           maxPower,
105			FromRev:            fromRev,
106		}
107		spec.ApplyDefaults()
108		if err := spec.Validate(); err != nil {
109			return executeloop.ExecuteLoopSpec{}, executeloop.DispatchOptions{}, err
110		}
111	
112		return spec, executeloop.DispatchOptions{Local: local, JSON: dispatchJSON}, nil
113	}
