126	func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
127		spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
128		if err != nil {
129			return err
130		}
131		projectRoot := resolveProjectRoot(spec.ProjectRoot, f.WorkingDir)
132		spec.ProjectRoot = projectRoot
133		if tryTargetBeadID != "" {
134			spec.Mode = executeloop.ModeOnce
135			spec.IdleInterval = executeloop.Duration{}
136		}
137	
138		noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
139			spec.Profile == "" && spec.MinPower == 0 &&
140			spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
141			!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
142			!cmd.Flags().Changed("profile") &&
143			!cmd.Flags().Changed("min-power") && !cmd.Flags().Changed("max-power")
144		autoInferTier := noRoutingFlags && !projectHasRoutingConfig(projectRoot)
145	
146		if !spec.OpaquePassthrough {
147			if err := agent.ValidateForExecuteLoopViaService(cmd.Context(), f.WorkingDir, spec.Harness, spec.Model, spec.Provider); err != nil {
148				return fmt.Errorf("execute-loop: %w", err)
149			}
150		}
151	
152		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
153	
154		loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
155		loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
156		_ = os.MkdirAll(loopLogDir, 0o755)
157		loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
158		var loopSink io.Writer
159		if lf, err := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); err == nil {
160			loopSink = lf
161			defer lf.Close() //nolint:errcheck
162		}
163	
164		probeIdent := workerprobe.Identity{
165			ProjectRoot:  projectRoot,
166			Harness:      spec.Harness,
167			Model:        spec.Model,
168			ExecutorPID:  os.Getpid(),
169			ExecutorHost: hostnameOrEmpty(),
170			StartedAt:    time.Now().UTC(),
171		}
172		probe := workerprobe.New(probeIdent, workerprobe.Config{AddrFunc: serverpkg.ReadServerAddr})
173		probeCtx, probeCancel := context.WithCancel(context.Background())
174		probe.Start(probeCtx)
175		defer func() {
176			probeCancel()
177			probe.Stop()
178		}()
179		if loopSink != nil {
180			loopSink = workerprobe.TeeJSONL(loopSink, probe)
181		} else {
182			loopSink = workerprobe.TeeJSONL(io.Discard, probe)
183		}
184	
185		localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
186		defer localCoord.Stop()
187	
188		var reviewer agent.BeadReviewer
189		if !spec.NoReview {
190			reviewer = &agent.DefaultBeadReviewer{
191				ProjectRoot: projectRoot,
192				BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
193				BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
194				Harness:     spec.ReviewHarness,
195				Model:       spec.ReviewModel,
196			}
197		}
198	
199		spec.Profile = agent.NormalizeRoutingProfile(spec.Profile)
200	
201		overrides := config.CLIOverrides{
202			Assignee:          resolveClaimAssignee(),
203			Harness:           spec.Harness,
204			Model:             spec.Model,
205			Provider:          spec.Provider,
206			Profile:           spec.Profile,
207			Effort:            spec.Effort,
208			MinPower:          spec.MinPower,
209			MaxPower:          spec.MaxPower,
210			OpaquePassthrough: spec.OpaquePassthrough,
211		}
212		rcfg, err := config.LoadAndResolve(projectRoot, overrides)
213		if err != nil {
214			return fmt.Errorf("load resolved config: %w", err)
215		}
216	
217		resourceChecker := buildCLIResourceChecker(projectRoot, f.resourceCheckerOverride)
218		if _, err := resourceChecker.Check(cmd.Context()); err != nil {
219			var resourceErr *agent.ResourceExhaustedError
220			if errors.As(err, &resourceErr) {
221				_, _ = fmt.Fprintln(cmd.OutOrStdout(), agent.ResourceExhaustedStopMessage)
222			}
223			return err
224		}
225	
226		var qualityRunner agent.AgentRunner
227		if f.AgentRunnerOverride != nil {
228			qualityRunner = f.AgentRunnerOverride
229		}
230		lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
231		innerIntakeHook := agent.NewPreClaimIntakeHook(projectRoot, store, rcfg, nil, qualityRunner)
232		intakeHook := agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), innerIntakeHook)
233		triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
234		decompositionHook := agent.NewPreClaimDecompositionHook(store, qualityRunner, rcfg, projectRoot)
235		recoveryHook := agent.NewAutoRecoveryPostLadderExhaustionHook(store, qualityRunner, rcfg, projectRoot, agent.AutoRecoveryConfig{
236			MaxRecoveryCostUSD: spec.MaxRecoveryCostUSD,
237			MaxBeadCostUSD:     spec.MaxBeadCostUSD,
238		})
239	
240		harnessBilledLookup := func(harnessName string) bool {
241			svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
242			if svcErr != nil {
243				return true
244			}
245			infos, err := svc.ListHarnesses(context.Background())
246			if err != nil {
247				return true
248			}
249			for _, h := range infos {
250				if h.Name == harnessName {
251					return escalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
252				}
253			}
254			return true
255		}
256	
257		costCap := escalation.NewCostCapTracker(spec.MaxCostUSD, harnessBilledLookup)
258		profileSelector := newImplementationProfileSelector(projectRoot)
259		accumulateBilledCost := func(report agent.ExecuteBeadReport) {
260			costCap.Add(report.Harness, report.CostUSD)
261		}
262		costCapTripped := func() (work.StopDecision, agent.ExecuteBeadReport, bool) {
263			if _, tripped := costCap.Tripped(); !tripped {
264				return work.StopDecision{}, agent.ExecuteBeadReport{}, false
265			}
266			spent := costCap.Spent()
267			decision, _ := work.ClassifyStop(work.StopInput{Budget: true})
268			return decision, agent.ExecuteBeadReport{
269				Status: agent.ExecuteBeadStatusExecutionFailed,
270				Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, spec.MaxCostUSD),
271			}, true
272		}
273	
274		singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, requestedProfile string, requestedTier escalation.ModelTier, routingNote string, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
275			gitOps := &agent.RealGitOps{}
276			attemptProvider := spec.Provider
277			if resolvedProvider != "" {
278				attemptProvider = resolvedProvider
279			}
280			reportFromResult := func(res *agent.ExecuteBeadResult) agent.ExecuteBeadReport {
281				report := agent.ReportFromExecuteBeadResult(res, string(requestedTier))
282				report.RequestedTier = string(requestedTier)
283				report.RequestedProfile = requestedProfile
284				report.RoutingIntentNote = routingNote
285				return report
286			}
287			loopOverrides := config.CLIOverrides{
288				Harness:           resolvedHarness,
289				Model:             resolvedModel,
290				Provider:          attemptProvider,
291				Profile:           requestedProfile,
292				Effort:            spec.Effort,
293				MinPower:          requestedMinPower,
294				MaxPower:          spec.MaxPower,
295				OpaquePassthrough: spec.OpaquePassthrough,
296			}
297			requestTimeout := spec.RequestTimeout.Duration
298			if requestTimeout > 0 {
299				loopOverrides.ProviderRequestTimeout = &requestTimeout
300			}
301			attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
302			res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, executeLoopAttemptRuntime(
303				spec,
304				cmd.OutOrStdout(),
305				bead.NewStore(filepath.Join(projectRoot, ".ddx")),
306				f.AgentRunnerOverride,
307				resourceChecker,
308			), gitOps)
309			if execErr != nil && res == nil {
310				return agent.ExecuteBeadReport{}, execErr
311			}
312			if res != nil && agent.IsResourceExhaustedStatus(res.Status) {
313				return reportFromResult(res), nil
314			}
315			if execErr != nil {
316				agent.MarkResultExecutionError(res, execErr)
317				return reportFromResult(res), nil
318			}
319			if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
320				targetBead, _ := store.Get(context.Background(), beadID)
321				landRes, _, landErr := agent.SubmitWithPreMergeChecks(
322					ctx, projectRoot, targetBead, res,
323					func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
324					bead.NewStore(filepath.Join(projectRoot, ".ddx")),
325					resolveClaimAssignee(), "ddx work",
326					nil,
327				)
328				if landErr == nil {
329					agent.ApplyLandResultToExecuteBeadResult(res, landRes)
330					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
331				} else {
332					agent.MarkResultLandError(projectRoot, res, landErr)
333					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
334					return reportFromResult(res), nil
335				}
336			} else if res != nil && (res.Outcome == agent.ExecuteBeadOutcomeTaskFailed || res.ExitCode != 0) {
337				if res.ResultRev != "" && res.ResultRev != res.BaseRev {
338					res.Outcome = "preserved"
339				} else {
340					res.Outcome = "error"
341				}
342				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
343			} else if res != nil && res.ResultRev == res.BaseRev {
344				res.Outcome = "no-changes"
345				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
346			}
347			return reportFromResult(res), nil
348		}
349	
350		var ladderOnce sync.Once
351		var ladder escalationFloorFinder
352		loadLadder := func() escalationFloorFinder {
353			ladderOnce.Do(func() {
354				ladder = tierescalation.NewLadder(nil)
355				svc, svcErr := agent.ResolveServiceFromWorkDir(projectRoot)
356				if svcErr != nil {
357					return
358				}
359				modelFilter := agentlib.ModelFilter{}
360				if spec.Harness != "" {
361					modelFilter.Harness = spec.Harness
362				}
363				modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
364				defer cancel()
365				models, listErr := svc.ListModels(modelCtx, modelFilter)
366				if listErr != nil {
367					return
368				}
369				ladder = tierescalation.NewLadder(models)
370			})
371			return ladder
372		}
373	
374		worker := &agent.ExecuteBeadWorker{
375			Store:    store,
376			Reviewer: reviewer,
377			EscalationNextFloor: func(actualPower int) (int, error) {
378				return nextEscalationFloor(loadLadder(), actualPower)
379			},
380			Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
381				targetBead, err := store.Get(context.Background(), beadID)
382				if err != nil {
383					return agent.ExecuteBeadReport{}, err
384				}
385				inferredTier := escalation.ModelTier("")
386				if autoInferTier {
387					inferredTier = escalation.InferTier(targetBead)
388				}
389				initialMinPower, unavailableReport, unavailable := investigationRetryInitialMinPowerWithInference(targetBead, rcfg.MinPower(), spec.MaxPower, loadLadder(), false)
390				if unavailable {
391					return unavailableReport, nil
392				}
393				initialProfile := spec.Profile
394				initialRoutingNote := ""
395				if autoInferTier {
396					if selection, selectErr := profileSelector.Select(ctx, inferredTier, initialMinPower); selectErr == nil && selection.Name != "" {
397						initialProfile = selection.Name
398						initialRoutingNote = selection.Note
399						if selection.MinPower > initialMinPower {
400							initialMinPower = selection.MinPower
401						}
402						if spec.MaxPower > 0 && initialMinPower >= spec.MaxPower {
403							unavailableReport := smartRouteUnavailableReport(targetBead, initialMinPower, spec.MaxPower, nil)
404							unavailableReport.RequestedTier = string(inferredTier)
405							unavailableReport.RequestedProfile = initialProfile
406							unavailableReport.RoutingIntentNote = initialRoutingNote
407							return unavailableReport, nil
408						}
409					} else {
410						initialMinPower, unavailableReport, unavailable = zeroConfigInferredMinPower(targetBead, initialMinPower, spec.MaxPower, loadLadder())
411						if unavailable {
412							unavailableReport.RequestedTier = string(inferredTier)
413							return unavailableReport, nil
414						}
415					}
416				}
417				perBeadBudget := spec.MaxBeadCostUSD
418				if override, ok := escalation.ParseBeadBudgetLabel(targetBead.Labels); ok {
419					perBeadBudget = override
420				}
421				perBeadTracker := escalation.NewPerBeadCostTracker(perBeadBudget, harnessBilledLookup)
422				report, err := runEscalatingSingleTierAttempts(
423					ctx,
424					initialMinPower,
425					loadLadder(),
426					func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
427						requestProfile := initialProfile
428						routingNote := initialRoutingNote
429						if autoInferTier {
430							if selection, selectErr := profileSelector.Select(ctx, inferredTier, requestedMinPower); selectErr == nil {
431								// Empty selection means no no-extra-requirement policy covers this
432								// retry floor. Drop the stale lower policy and send MinPower-only so
433								// Fizeau can route or report no eligible candidate from live config.
434								requestProfile = selection.Name
435								if requestProfile == "" {
436									routingNote = ""
437								} else if selection.Note != "" {
438									routingNote = selection.Note
439								}
440							}
441						}
442						return singleTierAttempt(ctx, beadID, requestedMinPower, requestProfile, inferredTier, routingNote, spec.Harness, spec.Provider, spec.Model)
443					},
444					nil,
445					perBeadTracker,
446				)
447				if err == nil {
448					accumulateBilledCost(report)
449				}
450				return report, err
451			}),
452		}
453	
454		cliLandingOps := agent.RealLandingGitOps{}
455		progressLog := cmd.OutOrStdout()
456		cleanupLog := cmd.ErrOrStderr()
457		jsonOutput := dispatch.JSON == "true"
458		if jsonOutput {
459			progressLog = io.Discard
460			cleanupLog = io.Discard
461		}
462		result, err := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
463			Mode:                         spec.Mode,
464			IdleInterval:                 spec.IdleInterval.Duration,
465			Log:                          progressLog,
466			CleanupLog:                   cleanupLog,
467			EventSink:                    loopSink,
468			WorkerID:                     resolveClaimAssignee(),
469			ProjectRoot:                  projectRoot,
470			CleanupRunner:                agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{}),
471			ResourceChecker:              resourceChecker,
472			BinaryRefreshCheck:           f.buildWorkBinaryRefreshCheck(cmd, projectRoot, tryTargetBeadID),
473			SessionID:                    loopSessionID,
474			PreClaimHook:                 buildCLIPreClaimHook(projectRoot, cliLandingOps),
475			PreClaimIntakeHook:           intakeHook,
476			PreDispatchLintHook:          lintHook,
477			PostAttemptTriageHook:        triageHook,
478			PostAttemptDecompositionHook: decompositionHook,
479			BudgetStop:                   costCapTripped,
480			NoReview:                     spec.NoReview,
481			TargetBeadID:                 tryTargetBeadID,
482			ReviewCostCap:                costCap,
483			OnAttemptFinalized:           buildAttemptMetricsHook(projectRoot, store, spec.Profile),
484			PostLadderExhaustionHook:     recoveryHook,
485		})
486		if err != nil && result != nil && (errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)) {
487			_ = writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
488		}
489		if err != nil {
490			return err
491		}
492		if result != nil && result.ExitReason == "binary_refresh" {
493			return nil
494		}
495		return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
496	}
