498	func buildAttemptMetricsHook(projectRoot string, store *bead.Store, profile string) func(agent.ExecuteBeadReport) {
499		return func(report agent.ExecuteBeadReport) {
500			if report.AttemptID == "" {
501				return
502			}
503			specID := ""
504			if report.BeadID != "" && store != nil {
505				if b, err := store.Get(context.Background(), report.BeadID); err == nil {
506					specID, _ = b.Extra["spec-id"].(string)
507				}
508			}
509			tsEnd := attemptmetrics.Rfc3339(time.Now().UTC())
510			tsStart := ""
511			if report.DurationMS > 0 {
512				start := time.Now().UTC().Add(-time.Duration(report.DurationMS) * time.Millisecond)
513				tsStart = attemptmetrics.Rfc3339(start)
514			}
515			row := attemptmetrics.AttemptRow{
516				SchemaVersion: attemptmetrics.SchemaVersion,
517				AttemptID:     report.AttemptID,
518				BeadID:        report.BeadID,
519				SessionID:     report.SessionID,
520				TSStart:       tsStart,
521				TSEnd:         tsEnd,
522				Model:         report.Model,
523				Harness:       report.Harness,
524				Profile:       profile,
525				Provider:      report.Provider,
526				SpecID:        specID,
527				Outcome:       report.Status,
528				CostUSD:       report.CostUSD,
529				DurationMS:    int(report.DurationMS),
530				ReviewVerdict: report.ReviewVerdict,
531			}
532			_ = attemptmetrics.AppendRow(projectRoot, row)
533		}
534	}
