536	func projectHasRoutingConfig(projectRoot string) bool {
537		if projectRoot == "" {
538			return false
539		}
540		cfgPath := filepath.Join(projectRoot, ".ddx", "config.yaml")
541		if _, err := os.Stat(cfgPath); err != nil {
542			return false
543		}
544		cfg, err := config.LoadWithWorkingDir(projectRoot)
545		if err != nil || cfg == nil || cfg.Agent == nil {
546			return false
547		}
548		a := cfg.Agent
549		if strings.TrimSpace(a.Model) != "" {
550			return true
551		}
552		if len(a.Endpoints) > 0 {
553			return true
554		}
555		return false
