23	func (s *implementationProfileSelector) Select(ctx context.Context, tier escalation.ModelTier, floor int) (agent.ImplementationProfileSelection, error) {
24		if s == nil {
25			return agent.ImplementationProfileSelection{}, nil
26		}
27		s.once.Do(func() {
28			svc, err := agent.ResolveServiceFromWorkDir(s.projectRoot)
29			if err != nil {
30				s.err = err
31				return
32			}
33			snapCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
34			defer cancel()
35			s.snap, s.err = agent.LoadProfileSnapshot(snapCtx, svc)
36		})
37		if s.err != nil {
38			return agent.ImplementationProfileSelection{}, s.err
39		}
40		if tier == "" {
41			tier = escalation.TierCheap
42		}
43		if floor > 0 {
44			return agent.SelectImplementationProfileForMinPower(s.snap, tier, floor), nil
45		}
46		return agent.SelectImplementationProfile(s.snap, tier), nil
47	}
