1	package agent
2	
3	import (
4		"context"
5		"math"
6		"reflect"
7		"sort"
8		"strings"
9		"sync"
10		"time"
11	
12		"github.com/DocumentDrivenDX/ddx/internal/escalation"
13		agentlib "github.com/easel/fizeau"
14	)
15	
16	const profileSnapshotCacheWindow = 30 * time.Second
17	
18	var (
19		profileSnapshotCacheMu sync.Mutex
20		profileSnapshotCache   = map[agentlib.FizeauService]profileSnapshotCacheEntry{}
21		profileSnapshotNow     = time.Now
22	)
23	
24	type profileSnapshotCacheEntry struct {
25		snap     ProfileSnapshot
26		loadedAt time.Time
27	}
28	
29	// ProfileSnapshot is the fizeau-owned routing vocabulary DDx uses for hidden
30	// lifecycle dispatches. DDx selects policy names from this snapshot; it does
31	// not resolve concrete models.
32	type ProfileSnapshot struct {
33		Profiles []agentlib.PolicyInfo
34		Models   []agentlib.ModelInfo
35	}
36	
37	type ImplementationProfileSelection struct {
38		Name     string
39		MinPower int
40		Degraded bool
41		Note     string
42	}
43	
44	// LoadProfileSnapshot fetches fizeau profiles and models with short-lived,
45	// stale-on-error memoization keyed to the service identity.
46	func LoadProfileSnapshot(ctx context.Context, svc agentlib.FizeauService) (ProfileSnapshot, error) {
47		if svc == nil {
48			return ProfileSnapshot{}, nil
49		}
50		key, cacheable := profileSnapshotCacheKey(svc)
51		now := profileSnapshotNow()
52	
53		var last profileSnapshotCacheEntry
54		var hadLast bool
55		if cacheable {
56			profileSnapshotCacheMu.Lock()
57			if entry, ok := profileSnapshotCache[key]; ok && now.Sub(entry.loadedAt) < profileSnapshotCacheWindow {
58				snap := cloneProfileSnapshot(entry.snap)
59				profileSnapshotCacheMu.Unlock()
60				return snap, nil
61			}
62			last, hadLast = profileSnapshotCache[key]
63			profileSnapshotCacheMu.Unlock()
64		}
65	
66		profiles, err := svc.ListPolicies(ctx)
67		if err != nil {
68			if hadLast {
69				return cloneProfileSnapshot(last.snap), nil
70			}
71			return ProfileSnapshot{}, err
72		}
73		models, err := svc.ListModels(ctx, agentlib.ModelFilter{})
74		if err != nil {
75			if hadLast {
76				return cloneProfileSnapshot(last.snap), nil
77			}
78			return ProfileSnapshot{}, err
79		}
80	
81		snap := ProfileSnapshot{
82			Profiles: append([]agentlib.PolicyInfo(nil), profiles...),
83			Models:   append([]agentlib.ModelInfo(nil), models...),
84		}
85		if cacheable {
86			profileSnapshotCacheMu.Lock()
87			profileSnapshotCache[key] = profileSnapshotCacheEntry{snap: cloneProfileSnapshot(snap), loadedAt: now}
88			profileSnapshotCacheMu.Unlock()
89		}
90		return snap, nil
91	}
92	
93	func profileSnapshotCacheKey(svc agentlib.FizeauService) (agentlib.FizeauService, bool) {
94		t := reflect.TypeOf(svc)
95		if t == nil || !t.Comparable() {
96			return nil, false
97		}
98		return svc, true
99	}
100	
101	func cloneProfileSnapshot(snap ProfileSnapshot) ProfileSnapshot {
102		return ProfileSnapshot{
103			Profiles: append([]agentlib.PolicyInfo(nil), snap.Profiles...),
104			Models:   append([]agentlib.ModelInfo(nil), snap.Models...),
105		}
106	}
107	
108	// SelectCheapestProfile returns the lowest-power profile band that has at least
109	// one available, auto-routable model.
110	func SelectCheapestProfile(snap ProfileSnapshot) string {
111		profiles := satisfiableProfiles(snap, 0)
112		sort.SliceStable(profiles, func(i, j int) bool {
113			left, right := profiles[i], profiles[j]
114			if profileMaxForSort(left) != profileMaxForSort(right) {
115				return profileMaxForSort(left) < profileMaxForSort(right)
116			}
117			if left.MinPower != right.MinPower {
118				return left.MinPower < right.MinPower
119			}
120			return preferProfile(left, right)
121		})
122		if len(profiles) == 0 {
123			return ""
124		}
125		return profiles[0].Name
126	}
127	
128	// SelectStrongestProfile returns the highest-power profile band that has at
129	// least one available, auto-routable model.
130	func SelectStrongestProfile(snap ProfileSnapshot) string {
131		profiles := satisfiableProfiles(snap, 0)
132		sort.SliceStable(profiles, func(i, j int) bool {
133			left, right := profiles[i], profiles[j]
134			if left.MinPower != right.MinPower {
135				return left.MinPower > right.MinPower
136			}
137			if profileMaxForSort(left) != profileMaxForSort(right) {
138				return profileMaxForSort(left) > profileMaxForSort(right)
139			}
140			return preferProfile(left, right)
141		})
142		if len(profiles) == 0 {
143			return ""
144		}
145		return profiles[0].Name
146	}
147	
148	// SelectStrongestProfileAbove returns the strongest satisfiable profile whose
149	// lower bound is at least floor.
150	func SelectStrongestProfileAbove(snap ProfileSnapshot, floor int) string {
151		profiles := satisfiableProfiles(snap, floor)
152		sort.SliceStable(profiles, func(i, j int) bool {
153			left, right := profiles[i], profiles[j]
154			if left.MinPower != right.MinPower {
155				return left.MinPower > right.MinPower
156			}
157			if profileMaxForSort(left) != profileMaxForSort(right) {
158				return profileMaxForSort(left) > profileMaxForSort(right)
159			}
160			return preferProfile(left, right)
161		})
162		if len(profiles) == 0 {
163			return ""
164		}
165		return profiles[0].Name
166	}
167	
168	// SelectImplementationProfile chooses an opaque Fizeau profile name for
169	// implementation work. It ranks by policy metadata, not by hard-coded policy
170	// names. Ordinary auto-routing avoids profiles with hard requirements (for
171	// example local-only/no-remote policy requirements) unless DDx has an explicit
172	// matching intent; explicit --profile remains a raw passthrough handled by
173	// Fizeau.
174	func SelectImplementationProfile(snap ProfileSnapshot, tier escalation.ModelTier) ImplementationProfileSelection {
175		return selectImplementationProfile(snap, tier, 0)
176	}
177	
178	// SelectImplementationProfileForMinPower chooses an implementation profile
179	// whose advertised power range can satisfy the requested lower bound. It is
180	// used by retry escalation so DDx does not keep a weak profile pinned after it
181	// has raised MinPower beyond that profile's range.
182	func SelectImplementationProfileForMinPower(snap ProfileSnapshot, tier escalation.ModelTier, floor int) ImplementationProfileSelection {
183		return selectImplementationProfile(snap, tier, floor)
184	}
185	
186	func selectImplementationProfile(snap ProfileSnapshot, tier escalation.ModelTier, floor int) ImplementationProfileSelection {
187		profiles := implementationCandidateProfiles(snap, floor)
188		if len(profiles) == 0 {
189			return ImplementationProfileSelection{}
190		}
191		selected, note := chooseImplementationCandidate(profiles, tier, floor)
192		return ImplementationProfileSelection{
193			Name:     selected.Name,
194			MinPower: selected.MinPower,
195			Degraded: note != "",
196			Note:     note,
197		}
198	}
199	
200	func implementationCandidateProfiles(snap ProfileSnapshot, floor int) []agentlib.PolicyInfo {
201		profiles := satisfiableProfiles(snap, 0)
202		out := make([]agentlib.PolicyInfo, 0, len(profiles))
203		for _, profile := range profiles {
204			if hasHardPolicyRequirement(profile) {
205				continue
206			}
207			if floor > 0 && profileMaxForSort(profile) < floor {
208				continue
209			}
210			out = append(out, profile)
211		}
212		sort.SliceStable(out, func(i, j int) bool {
213			return implementationProfileLess(snap, out[i], out[j])
214		})
215		return out
216	}
217	
218	func chooseImplementationCandidate(profiles []agentlib.PolicyInfo, tier escalation.ModelTier, floor int) (agentlib.PolicyInfo, string) {
219		if floor > 0 && tier != escalation.TierSmart {
220			return profiles[0], ""
221		}
222		switch tier {
223		case escalation.TierSmart:
224			return profiles[len(profiles)-1], ""
225		case escalation.TierStandard:
226			if selected, ok := firstBandAboveLowest(profiles); ok {
227				return selected, ""
228			}
229			return profiles[0], "medium profile unavailable; using only available profile"
230		case escalation.TierCheap, "":
231			return profiles[0], ""
232		default:
233			return profiles[0], ""
234		}
235	}
236	
237	func firstBandAboveLowest(profiles []agentlib.PolicyInfo) (agentlib.PolicyInfo, bool) {
238		if len(profiles) <= 1 {
239			return agentlib.PolicyInfo{}, false
240		}
241		lowest := profiles[0]
242		for _, profile := range profiles[1:] {
243			if profile.MinPower > lowest.MinPower || profileMaxForSort(profile) > profileMaxForSort(lowest) {
244				return profile, true
245			}
246		}
247		return agentlib.PolicyInfo{}, false
248	}
249	
250	func hasHardPolicyRequirement(profile agentlib.PolicyInfo) bool {
251		for _, requirement := range profile.Require {
252			if strings.TrimSpace(requirement) != "" {
253				return true
254			}
255		}
256		return false
257	}
258	
259	func satisfiableProfiles(snap ProfileSnapshot, floor int) []agentlib.PolicyInfo {
260		out := make([]agentlib.PolicyInfo, 0, len(snap.Profiles))
261		for _, profile := range snap.Profiles {
262			if profile.Name == "" {
263				continue
264			}
265			if profile.MinPower == 0 && profile.MaxPower == 0 {
266				continue
267			}
268			if floor > 0 && profile.MinPower < floor {
269				continue
270			}
271			if profileHasAvailableModel(profile, snap.Models) {
272				out = append(out, profile)
273			}
274		}
275		return out
276	}
277	
278	func profileHasAvailableModel(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) bool {
279		for _, model := range models {
280			if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
281				continue
282			}
283			if profile.MinPower > 0 && model.Power < profile.MinPower {
284				continue
285			}
286			if profile.MaxPower > 0 && model.Power > profile.MaxPower {
287				continue
288			}
289			return true
290		}
291		return false
292	}
