294	func implementationProfileLess(snap ProfileSnapshot, left, right agentlib.PolicyInfo) bool {
295		if profileMaxForSort(left) != profileMaxForSort(right) {
296			return profileMaxForSort(left) < profileMaxForSort(right)
297		}
298		if left.MinPower != right.MinPower {
299			return left.MinPower < right.MinPower
300		}
301		leftCost, leftCostOK := profileBestCost(left, snap.Models)
302		rightCost, rightCostOK := profileBestCost(right, snap.Models)
303		if leftCostOK != rightCostOK {
304			return leftCostOK
305		}
306		if leftCostOK && rightCostOK && leftCost != rightCost {
307			return leftCost < rightCost
308		}
309		leftSpeed, leftSpeedOK := profileBestSpeed(left, snap.Models)
310		rightSpeed, rightSpeedOK := profileBestSpeed(right, snap.Models)
311		if leftSpeedOK != rightSpeedOK {
312			return leftSpeedOK
313		}
314		if leftSpeedOK && rightSpeedOK && leftSpeed != rightSpeed {
315			return leftSpeed > rightSpeed
316		}
317		return left.Name < right.Name
318	}
