336	func profileBestSpeed(profile agentlib.PolicyInfo, models []agentlib.ModelInfo) (float64, bool) {
337		best := 0.0
338		ok := false
339		for _, model := range models {
340			if !modelFitsProfile(profile, model) {
341				continue
342			}
343			speed := model.PerfSignal.SpeedTokensPerSec
344			if speed <= 0 {
345				continue
346			}
347			if !ok || speed > best {
348				best = speed
349				ok = true
350			}
351		}
352		return best, ok
353	}
