355	func modelFitsProfile(profile agentlib.PolicyInfo, model agentlib.ModelInfo) bool {
356		if !model.Available || !model.AutoRoutable || model.ExactPinOnly {
357			return false
358		}
359		if profile.MinPower > 0 && model.Power < profile.MinPower {
360			return false
361		}
362		if profile.MaxPower > 0 && model.Power > profile.MaxPower {
363			return false
364		}
365		return true
366	}
