24	func nextEscalationFloor(l escalationFloorFinder, actualPower int) (int, error) {
25		if l == nil {
26			return 0, tierescalation.ErrLadderExhausted
27		}
28		floor := actualPower
29		for {
30			next, err := l.Next(floor)
31			if err == nil {
32				return next, nil
33			}
34			var nvp *tierescalation.NoViableProviderError
35			if errors.As(err, &nvp) {
36				floor = nvp.Floor
37				continue
38			}
39			return 0, err
40		}
41	}
42	
43	func highestViableEscalationFloor(l escalationFloorFinder) (int, error) {
44		if l == nil {
45			return 0, tierescalation.ErrLadderExhausted
46		}
47		floor := 0
48		highest := 0
49		for {
50			next, err := nextEscalationFloor(l, floor)
51			if err != nil {
52				if errors.Is(err, tierescalation.ErrLadderExhausted) && highest > 0 {
53					return highest, nil
54				}
55				return 0, err
56			}
57			highest = next
58			floor = next
59		}
60	}
