113	func resolveTierFloor(tier policyescalation.ModelTier, ladder escalationFloorFinder) (int, bool) {
114		switch tier {
115		case policyescalation.TierSmart:
116			floor, err := highestViableEscalationFloor(ladder)
117			if err != nil {
118				return 0, false
119			}
120			return floor, true
121		case policyescalation.TierStandard:
122			first, err := nextEscalationFloor(ladder, 0)
123			if err != nil {
124				return 0, false
125			}
126			second, err := nextEscalationFloor(ladder, first)
127			if err != nil {
128				return first, true
129			}
130			return second, true
131		default:
132			return 0, false
133		}
134	}
