136	func zeroConfigInferredMinPower(b *bead.Bead, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
137		tier := policyescalation.InferTier(b)
138		if tier == "" {
