140		}
141		tierFloor, hasTierFloor := resolveTierFloor(tier, ladder)
142		if !hasTierFloor && tier != policyescalation.TierCheap {
143			return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, fmt.Errorf("no viable routing floor for inferred tier %s", tier)), true
144		}
145		if tierFloor > baseMinPower {
146			if maxPower > 0 && tierFloor >= maxPower {
147				return baseMinPower, smartRouteUnavailableReport(b, tierFloor, maxPower, nil), true
148			}
149			return tierFloor, agent.ExecuteBeadReport{}, false
150		}
151		return baseMinPower, agent.ExecuteBeadReport{}, false
152	}
