181		}
182		switch strings.ToLower(strings.TrimSpace(fmt.Sprint(raw))) {
183		case string(policyescalation.TierSmart):
184			return policyescalation.TierSmart, true
185		case string(policyescalation.TierStandard):
186			return policyescalation.TierStandard, true
187		case string(policyescalation.TierCheap):
