660	func runEscalatingSingleTierAttempts(
661		ctx context.Context,
662		initialMinPower int,
663		ladder *tierescalation.Ladder,
664		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
665		recordAttempt func(agent.ExecuteBeadReport),
666	) (agent.ExecuteBeadReport, error) {
667		minPower := initialMinPower
668		for {
669			report, err := attempt(ctx, minPower)
670			if recordAttempt != nil && report.BeadID != "" {
671				recordAttempt(report)
672			}
673			if err != nil {
674				return report, err
675			}
676			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
677				return report, nil
678			}
679			basis := minPower
680			if report.ActualPower > 0 {
681				basis = report.ActualPower
682			}
683			nextPower, nextErr := nextEscalationFloor(ladder, basis)
684			if nextErr != nil {
685				return report, nil
686			}
687			minPower = nextPower
688		}
689	}
